class Solution {
    public List<Integer> diffWaysToCompute(String expression) {
        List<Integer> result = new ArrayList<>();
        int[] nums = parseExpression(expression);
        dfs(nums, 0, new ArrayList<Integer>(), result);
        return result;
    }

    private int[] parseExpression(String expression) {
        String[] tokens = expression.split("[+-*/]");
        int[] nums = new int[tokens.length];
        for (int i = 0; i < tokens.length; i++) {
            nums[i] = Integer.parseInt(tokens[i]);
        }
        return nums;
    }

    private void dfs(int[] nums, int index, List<Integer> stack, List<Integer> result) {
        if (index == nums.length) {
            result.add(stack.stream().reduce((a, b) -> a * b).orElse(0));
            return;
        }

        for (int i = 0; i < 4; i++) {
            if (nums[index] == 0) {
                stack.add(nums[index]);
            } else if (nums[index] > 0) {
                stack.add(nums[index]);
            } else {
                stack.add(-nums[index]);
            }
            dfs(nums, index + 1, stack, result);
            stack.pop();
        }
    }
}
